                    .iter()
                    .position(|&b| b == 0)
                    .unwrap_or(ar.short_src.len());
                let mut buf: Vec<u8> = ar.short_src[..zero].to_vec();
                buf.push(b':');
                buf.extend_from_slice(ar.currentline.to_string().as_bytes());
                buf.extend_from_slice(b": ");
