/// C: `LUALIB_API int luaL_newmetatable(lua_State *L, const char *tname)`
pub fn new_metatable(&mut self, tname: &[u8]) -> Result<bool, LuaError> {
    if get_field(self, LUA_REGISTRYINDEX, tname)? != LuaType::Nil {
        return Ok(false);
