/// `luaL_checkversion` is a no-op here (no ABI-version mismatch is
/// possible inside the Rust port).
pub fn new_lib(
    &mut self,
    funcs: &[(&[u8], LuaCFunction)],
) -> Result<(), LuaError> {
    create_table(self, 0, funcs.len() as i32)?;
